import React, { useEffect, useState } from 'react';
import './CommandeForm.css'; // <-- Import du CSS

function CommandeForm({ onCommandeAdded }) {
  const [clients, setClients] = useState([]);
  const [articles, setArticles] = useState([]);
  const [commande, setCommande] = useState({
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });
  const [message, setMessage] = useState('');
  const [isError, setIsError] = useState(false); // pour différencier les messages

  useEffect(() => {
    fetch('http://localhost:3001/clients')
      .then(res => res.json())
      .then(data => setClients(data));

    fetch('http://localhost:3001/articles')
      .then(res => res.json())
      .then(data => setArticles(data));
  }, []);

  const handleChange = e => {
    setCommande({ ...commande, [e.target.name]: e.target.value });
  };

  const handleSubmit = e => {
    e.preventDefault();
    fetch('http://localhost:3001/commandes', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(commande)
    })
      .then(res => res.json())
      .then(data => {
        setMessage(data.message || 'Commande ajoutée');
        setIsError(false);
        setCommande({ codeCli: '', codeArt: '', dateCom: '', QteCom: '' });
        if (onCommandeAdded) onCommandeAdded();
      })
      .catch(err => {
        console.error('Erreur ajout commande:', err);
        setMessage('Erreur lors de l’ajout');
        setIsError(true);
      });
  };

  return (
    <div className="commande-form">

      {message && (
        <p className={isError ? 'error-message' : 'success-message'}>{message}</p>
      )}
      <form onSubmit={handleSubmit}>
        <label>Client :</label>
        <select name="codeCli" value={commande.codeCli} onChange={handleChange} required>
          <option value="">-- Choisir un client --</option>
          {clients.map(c => (
            <option key={c.codeCli} value={c.codeCli}>
              {c.nomCli} {c.prenomCli}
            </option>
          ))}
        </select>

        <label>Article :</label>
        <select name="codeArt" value={commande.codeArt} onChange={handleChange} required>
          <option value="">-- Choisir un article --</option>
          {articles.map(a => (
            <option key={a.codeArt} value={a.codeArt}>
              {a.nomArt}
            </option>
          ))}
        </select>

        <label>Date :</label>
        <input type="date" name="dateCom" value={commande.dateCom} onChange={handleChange} required />

        <label>Quantité :</label>
        <input type="text" name="QteCom" value={commande.QteCom} onChange={handleChange} required />

        <button type="submit">Ajouter</button>
      </form>
    </div>
  );
}

export default CommandeForm;
